args.sparql:
SELECT DISTINCT ?range WHERE {
  ?range wdt:P31 wd:Q3715490.
  ?range wdt:P148 ?elevation.
  ?elevation wikibase:quantityAmount ?height.
  FILTER(?height > 5600)
}

SELECT ?highestPeak ?height WHERE {
  wd:Q2448 wdt:P148 ?highestPeak.
  ?highestPeak wdt:P2044 ?elevation.
  ?elevation wikibase:quantityAmount ?height.
  FILTER(?height > 5600)
}
